u_idp_action_form.execution_script:
// Create service record
var service = new GlideRecord('cmdb_ci_service_auto');
service.initialize();
service.setValue('name', formData.service_name);
service.setValue('short_description', formData.service_description);
service.setValue('owned_by', userId);
service.setValue('service_type', formData.service_type);
service.setValue('language', formData.language);
service.setValue('framework', formData.framework);
var serviceId = service.insert();

// Trigger scaffolding workflow
var workflow = new Workflow();
workflow.startWorkflow('service_scaffolding', serviceId, {
    template: formData.template,
    git_provider: formData.git_provider
});

// Create initial scorecard
var scorecardEngine = new x_146833_idpkiro.IDPScorecardEngine();
scorecardEngine.createProductionReadinessScorecard(serviceId);

return {
    success: true,
    resourceId: serviceId,
    resourceType: 'service',
    message: 'Service scaffolding started. Check your Git repository.'
};
